#include <bits/stdc++.h>
using namespace std;
#define dbg(x) cerr<<#x" = "<<(x)<<endl;
#define ll long long
const int N=100005;
ll n,a[N][2],dp[N][2][2],du[N],vis[N];
vector<int> g[N];
int dfs(int u,int f)
{
	if(vis[u]) return u;
	vis[u]=1;
	for(int i=0;i<g[u].size();i++)
	{
		int v=g[u][i];
		if(v==f)
		{
			continue;
		}
		int tmp=dfs(v,u);
		if(tmp)
		{
			return tmp;
		}
	}
	vis[u]=0;
	return 0;
}
void dfs2(int u,int f)
{
	for(int i=0;i<g[u].size();i++)
	{
		int v=g[u][i];
		if((v==f)||vis[v]) continue;
		dfs2(v,u);
		a[u][0]+=max(a[v][1],a[v][0]);
		a[u][1]+=a[v][0];
	}
}
ll dfs3(int u,int f,int s)
{
//	cout<<u<<" "<<f<<" "<<a[u][0]<<" "<<a[u][1]<<"\n";
	if(u==s)
	{
		if(dp[u][1][1]) return max(dp[f][1][0],max(dp[f][0][0],dp[f][0][1]));
		dp[u][1][1]=a[u][1];
		dp[u][0][0]=a[u][0];
	}
	else
	{
		dp[u][1][1]=a[u][1]+dp[f][1][0];
		dp[u][1][0]=a[u][0]+max(dp[f][1][1],dp[f][1][0]);
		dp[u][0][1]=a[u][1]+dp[f][0][0];
		dp[u][0][0]=a[u][0]+max(dp[f][0][1],dp[f][0][0]);
	}
	for(int i=0;i<g[u].size();i++)
	{
		int v=g[u][i];
		if((v==f)||(!vis[v])) continue;
		return dfs3(v,u,s);
	}
}
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
//	freopen(".in","r",stdin);
//	freopen(".out","w",stdout);
	cin>>n;
	for(int i=1;i<=n;i++)
	{
		cin>>a[i][1];
	}
	for(int i=1;i<=n;i++)
	{
		int u,v;
		cin>>u>>v;
		u++;
		v++;
		g[u].push_back(v);
		g[v].push_back(u);
		du[u]++;
		du[v]++;
	}
	double k;
	cin>>k;
	int s=dfs(1,0);
	memset(vis,0,sizeof(vis));
	dfs(s,0);
	for(int i=1;i<=n;i++)
	{
		if((du[i]>2)&&vis[i])
		{
			dfs2(i,0);
		}
	}
	double tmp=dfs3(s,0,s);
	cout<<fixed<<setprecision(1)<<tmp*k;
	return 0;
}
